contributors:
{% for author_bundle in article.object.frozen_authors_for_jats_contribs %}
    {% with author=author_bundle.author affiliations=author_bundle.affiliations %}
        {% if author.is_corporate %}
            {{ author.corporate_name }}
        {% else %}

                {{ author.given_names }}
                {{ author.last_name }}

                {% if affiliations %}

                        {% for affil in affiliations %}
                            {% with org=affil.organization %}

                                    {{ org.name.value }}
                                    {% if org.ror_id %}
                                        {{ org.uri }}
                                    {% endif %}

                            {% endwith %}
                        {% endfor %}

                {% endif %}

                {% if author.orcid_uri %}
                    {{ author.orcid_uri }}
                {% endif %}

        {% endif %}
    {% endwith %}
{% empty %}

{% endfor %}
